commits.content:
.center-pos {
    top: 5%;
}

.popup-container .modal-inner {
    //padding: 20px;
    width: 40%;
		@media only screen and (max-width: 500px) {
			width: 90%;
		}
}
input.ng-invalid.ng-touched {
    border: red 1px solid;
}

.form-group {
	display: flex;
	flex-direction: column;
	align-items: flex-start;
	gap: 8px;
	flex: 1 0 0;
	width: 100%;
}

.form-label {
	display: flex;
	padding: 0 12px;
	align-items: flex-start;
	gap: 10px;
}

.form-input {
	display: flex;
	align-items: center;
	align-self: stretch;
	border-radius: 8px;
	border: 1px solid var(--ink-divide);
	background: rgba(0, 0, 0, 0.05);
	width: 100%;
}
.popup-container {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.6);
  z-index: 9999;
}

.modal-inner {
  pointer-events: auto;
}

.modal {
  pointer-events: none;
}
